SELECT id, fee_code, name, category, price, unit, status, remark, created_at, updated_at, deleted FROM clinic_fee_item WHERE deleted = 0
AND (fee_code LIKE CONCAT('%', #{keyword}, '%') OR name LIKE CONCAT('%', #{keyword}, '%') OR category LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE clinic_fee_item
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
